260	    public Object complete(JsonParser p, DeserializationContext ctxt,
261	            PropertyValueBuffer buffer, PropertyBasedCreator creator)
262	        throws IOException
263	    {
264	        // first things first: deserialize all data buffered:
265	        final int len = _properties.length;
266	        Object[] values = new Object[len];
267	        for (int i = 0; i < len; ++i) {
268	            String typeId = _typeIds[i];
269	            final ExtTypedProperty extProp = _properties[i];
270	            if (typeId == null) {
271	                // let's allow missing both type and property (may already have been set, too)
272	                TokenBuffer tb = _tokens[i];
273	                if ((tb == null)
274	                        // 19-Feb-2021, tatu: Both missing value and explicit `null`
275	                        //    should be accepted...
276	                        || (tb.firstToken() == JsonToken.VALUE_NULL)
277	                    ) {
278	                    continue;
279	                }
280	                // but not just one
281	                // 26-Oct-2012, tatu: As per [databind#94], must allow use of 'defaultImpl'
282	                if (!extProp.hasDefaultType()) {
283	                    ctxt.reportPropertyInputMismatch(_beanType, extProp.getProperty().getName(),
284	                            "Missing external type id property '%s'",
285	                            extProp.getTypePropertyName());
286	                } else {
287	                    typeId = extProp.getDefaultTypeId();
288	                }
289	            }
290	
291	            if (_tokens[i] != null) {
292	                values[i] = _deserialize(p, ctxt, i, typeId);
293	            } else {
294	                if (ctxt.isEnabled(DeserializationFeature.FAIL_ON_MISSING_EXTERNAL_TYPE_ID_PROPERTY)) {
295	                    SettableBeanProperty prop = extProp.getProperty();
296	                    ctxt.reportPropertyInputMismatch(_beanType, prop.getName(),
297	                            "Missing property '%s' for external type id '%s'",
298	                            prop.getName(), _properties[i].getTypePropertyName());
299	                }
300	                // 03-Aug-2022, tatu: [databind#3533] to handle absent value matching
301	                //    present type id
302	                values[i] = _deserializeMissingToken(p, ctxt, i, typeId);
303	            }
304	
305	            final SettableBeanProperty prop = extProp.getProperty();
306	            // also: if it's creator prop, fill in
307	            if (prop.getCreatorIndex() >= 0) {
308	                buffer.assignParameter(prop, values[i]);
309	
310	                // [databind#999] And maybe there's creator property for type id too?
311	                SettableBeanProperty typeProp = extProp.getTypeProperty();
312	                // for now, should only be needed for creator properties, too
313	                if ((typeProp != null) && (typeProp.getCreatorIndex() >= 0)) {
314	                    // 31-May-2018, tatu: [databind#1328] if id is NOT plain `String`, need to
315	                    //    apply deserializer... fun fun.
316	                    final Object v;
317	                    if (typeProp.getType().hasRawClass(String.class)) {
318	                        v = typeId;
319	                    } else {
320	                        TokenBuffer tb = ctxt.bufferForInputBuffering(p);
321	                        tb.writeString(typeId);
322	                        v = typeProp.getValueDeserializer().deserialize(tb.asParserOnFirstToken(), ctxt);
323	                        tb.close();
324	                    }
325	                    buffer.assignParameter(typeProp, v);
326	                }
327	            }
328	        }
329	        Object bean = creator.build(ctxt, buffer);
330	        // third: assign non-creator properties
331	        for (int i = 0; i < len; ++i) {
332	            SettableBeanProperty prop = _properties[i].getProperty();
333	            if (prop.getCreatorIndex() < 0) {
334	                prop.set(bean, values[i]);
335	            }
336	        }
337	        return bean;
338	    }

